const raw = $input.first().json.pendingText;

// 1. Пустой черновик — не рассылаем ничего
if (!raw || typeof raw !== 'string' || !raw.trim()) {
  throw new Error('STOP: черновик пустой. Рассылка отменена.');
}

const safe = raw.replace(/\r\n/g, '\n').trim();

// 2. Кириллица = мусор. Водителям пишем только на азербайджанском.
if (/[А-Яа-яЁё]/.test(safe)) {
  const found = (safe.match(/[А-Яа-яЁё]+/g) || []).slice(0, 5).join(' ');
  throw new Error('STOP: в черновике кириллица ("' + found + '"). Рассылка отменена.');
}

// 3. Служебный мусор: арифметика вида "22 % 12 = 10", годы 20xx
if (/\d+\s*%\s*\d+\s*=\s*\d+/.test(safe)) {
  throw new Error('STOP: в черновике арифметика. Рассылка отменена.');
}

// 4. Подозрительно короткий текст
if (safe.length < 15) {
  throw new Error('STOP: черновик слишком короткий (' + safe.length + ' симв.). Рассылка отменена.');
}

// 5. Подозрительно длинный (шаблон + погода ~ 200 симв.)
if (safe.length > 400) {
  throw new Error('STOP: черновик слишком длинный (' + safe.length + ' симв.). Рассылка отменена.');
}

return [{ json: { safeText: safe } }];

