      log.reason = 'COOKIE DEAD';
      return { data: JSON.stringify(log), type: 'application/json' };
    }
    await new Promise(r => setTimeout(r, 5000));

    const online = await page.evaluate(() => {
      try {
        const rows = window.$('#rows-table').jqxGrid('getrows');
        return rows
          .filter(r => r.online == 1 || r.online === true || r.online === '1')
          .map(r => ({ id: r.id, pozivnoi: r.pozivnoi, name: ((r.i||'') + ' ' + (r.f||'')).trim(), phone: r.phone_number }));
      } catch (e) { return []; }
    });
    log.steps.push('online total = ' + online.length);

    for (const d of online) {
      const ts = Date.now();
      try {
        await page.goto('https://1165.upphone.ru:4422/web/cab/1165/directory/drivers/id/' + d.id + '/track', { waitUntil: 'domcontentloaded', timeout: 20000 });
        let pos = null;
        for (let i = 0; i < 5; i++) {
