            if (typeof window.coords !== 'undefined' && Array.isArray(window.coords) && window.coords.length) {
              const last = window.coords[window.coords.length - 1];
              return { last: last, count: window.coords.length };
            }
            return null;
          });
          if (pos) break;
          await new Promise(r => setTimeout(r, 500));
        }
        if (pos && pos.last) {
          log.positions.push({
            id: d.id, pozivnoi: d.pozivnoi, name: d.name, phone: d.phone,
