try {
  fs.writeFileSync(file, JSON.stringify(out));
} catch (e) {
  return [{ json: { error: 'cannot write file: ' + String(e) } }];
}

return [{ json: {
  ok: true,
  wrote: clean.length + ' drivers',
  updated: out.updated,
