={{ JSON.stringify({ code: `
export default async function ({ page, context }) {
  const log = { steps: [], ok: false, sent: [], errors: [] };
  const positions = context.positions || [];
  const posAgeMin = context.updated ? Math.round((Date.now() - new Date(context.updated).getTime())/60000) : -1;
  const TEST_CHAT_ID = 5;
  const COMMISSION = 0.10, R1 = 4, R2 = 5, TOP_N = 5;

  function distKm(la1,ln1,la2,ln2){
    const R=6371,dLa=(la2-la1)*Math.PI/180,dLn=(ln2-ln1)*Math.PI/180;
    const a=Math.sin(dLa/2)**2+Math.cos(la1*Math.PI/180)*Math.cos(la2*Math.PI/180)*Math.sin(dLn/2)**2;
    return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
  }
  function firstName(f){ if(!f) return 'sürücü'; const w=String(f).trim().split(/\\s+/)[0]; return w.charAt(0).toUpperCase()+w.slice(1).toLowerCase(); }
  function sDA(w){ const b='aıou',v=(String(w).toLowerCase().match(/[aıoueəiöü]/g))||[],l=v.length?v[v.length-1]:'a'; return b.includes(l)?'da':'də'; }
  function sDAN(w){ return sDA(w)==='da'?'dan':'dən'; }
  function sA(w){ const b='aıou',v=(String(w).toLowerCase().match(/[aıoueəiöü]/g))||[],l=v.length?v[v.length-1]:'a'; return b.includes(l)?'a':'ə'; }

  try {
    await page.setCookie({ name:'cabinetUpTaxi', value: context.cookie, domain:'1165.upphone.ru', path:'/', httpOnly:false, secure:false });

    await page.goto('https://1165.upphone.ru:4422/web/cab/1165/monitoring/orders', { waitUntil:'networkidle2', timeout:60000 });
    if (page.url().includes('login.uptaxi.ru')) { log.reason='COOKIE DEAD'; return { data: JSON.stringify(log), type:'application/json' }; }

    await new Promise(r=>setTimeout(r,4000));

    // Берём первый горящий заказ без назначенного водителя
    const order = await page.evaluate(() => {
      try {
        const rows = window.$('#orders-table').jqxGrid('getrows');
        if (!rows || !rows.length) return null;
        const burning = rows.filter(r => String(r.status).toLowerCase().includes('burn') && (!r.pozivnoi || r.pozivnoi===''));
        const pick = burning.length ? burning[0] : rows[0];
        const flat = {};
        for (const k of Object.keys(pick)) { const v=pick[k]; if(v===null||['string','number','boolean'].includes(typeof v)) flat[k]=v; }
        return flat;
      } catch(e){ return { err:String(e) }; }
    });

    if (!order) { log.ok=true; log.verdict='Доска пуста — заказов нет сейчас'; return { data: JSON.stringify(log), type:'application/json' }; }
    log.orderRaw = order;

    // Пытаемся вытащить координаты подачи из разных возможных полей
    let oLat=null, oLng=null;
    const latKeys=['lat','from_lat','otkuda_lat','lat_a','latitude'];
    const lngKeys=['lng','lon','from_lng','otkuda_lng','lng_a','longitude'];
    for (const k of latKeys){ if(order[k]!=null && !isNaN(parseFloat(order[k]))){ oLat=parseFloat(order[k]); break; } }
    for (const k of lngKeys){ if(order[k]!=null && !isNaN(parseFloat(order[k]))){ oLng=parseFloat(order[k]); break; } }
    log.coordsSource = (oLat!=null&&oLng!=null) ? 'из полей заказа' : 'координат в заказе НЕТ';

    if (oLat==null || oLng==null) {
      // координат нет — показываем поля заказа, чтобы понять, где точка. Не шлём.
      log.ok=true;
      log.verdict='Заказ найден, но координат подачи нет в полях. Смотри orderRaw — определим, откуда брать точку. Ничего не отправлено.';
      return { data: JSON.stringify(log), type:'application/json' };
    }

    // считаем топ-5
    const zone = order.otkuda || order.zona || order.tarif || 'sifariş';
    const to = order.kuda || '';
    const price = parseFloat(order.price || order.summa || 0) || 0;
    const net = (price*(1-COMMISSION)).toFixed(2);

    const withDist = positions
      .filter(d=>typeof d.lat==='number'&&typeof d.lng==='number')
      .map(d=>({ id:d.id, pozivnoi:d.pozivnoi, name:d.name, km:Math.round(distKm(oLat,oLng,d.lat,d.lng)*100)/100 }))
      .sort((a,b)=>a.km-b.km);
    let picked = withDist.filter(d=>d.km<=R1).slice(0,TOP_N);
    if (picked.length<TOP_N) picked = withDist.filter(d=>d.km<=R2).slice(0,TOP_N);
    log.picked = picked;

    if (!picked.length) { log.ok=true; log.verdict='Заказ есть, но рядом (5км) никого. Позиции '+posAgeMin+' мин.'; return { data: JSON.stringify(log), type:'application/json' }; }

    // строим сообщения (в тесте все → id5, с пометкой кому)
    const zTxt = String(zone);
    const messages = picked.map(d=>{
      const nm=firstName(d.name);
      const body = nm+' bəy salam. '+zTxt+sDA(zTxt)+' bir sifariş var, qəbul edərsiniz? '+
        (to?(String(zone)+sDAN(zTxt)+' '+String(to)+sA(String(to))+' gedəcək, '):'')+
        'qiyməti '+price+' manatdı. Komissiyanı çıxanda '+net+' edir. '+
        'Yaxında sürücü olmadığı üçün sizə yazdım, ən yaxın sürücü sizsiniz.';
      return { poz:d.pozivnoi, text:'[TEST → '+d.pozivnoi+' | '+d.km+'km] '+body };
    });

    // отправляем в чат id5
    await page.goto('https://1165.upphone.ru:4422/web/cab/1165/directory/drivers/id/'+TEST_CHAT_ID+'/chat', { waitUntil:'networkidle2', timeout:60000 });
    await page.waitForSelector('input[name=message]', { timeout:15000 });
    for (const m of messages) {
      try {
        await page.click('input[name=message]', { clickCount:3 });
        await page.type('input[name=message]', m.text, { delay:20 });
        await page.click('button#send-chat-message');
        await new Promise(r=>setTimeout(r,1500));
        log.sent.push(m.poz);
      } catch(e){ log.errors.push(m.poz+':'+String(e).slice(0,40)); }
    }

    log.ok=true;
    log.verdict='Заказ '+zone+(to?(' → '+to):'')+' '+price+'₼. Рядом '+picked.length+', отправлено в id5: '+log.sent.length+'. Позиции '+posAgeMin+'мин';
    return { data: JSON.stringify(log), type:'application/json' };

  } catch (e) {
    log.error = String(e);
    return { data: JSON.stringify(log), type:'application/json' };
  }
}
`, context: { cookie: $json.cookie, positions: $json.positions, updated: $json.updated } }) }}

