  try {
    if (fs.existsSync(SENT)) {
      const arr = JSON.parse(fs.readFileSync(SENT, 'utf8'));
      if (Array.isArray(arr)) sent = arr;
    }
  } catch (e) {}

  const dayAgo = Date.now() - 24 * 60 * 60 * 1000;
  sent = sent.filter(x => x && x.ts && x.ts > dayAgo);

  pushed.forEach(p => sent.push({ id: p.id, ts: Date.now(), zone: p.zone, price: p.price }));

  try {
    if (!fs.existsSync(DIR)) fs.mkdirSync(DIR, { recursive: true });
    fs.writeFileSync(SENT, JSON.stringify(sent), 'utf8');
  } catch (e) {}
}

return [{
  json: {
    pushCount: pushed.length,
    pushed: pushed,
    ordersSeen: (payload.seen || []).length,
    cycles: payload.cycles,
    errors: payload.errors || []
  }
}];

