}

if (payload.error === 'COOKIE_DEAD') {
  return [{ json: { ok: false, note: 'COOKIE_DEAD — нужна свежая cookie' } }];
}

const s = Array.isArray(payload.stats) && payload.stats.length ? payload.stats[0] : {};
const b = payload.board || {};

const point = {
  ts: payload.ts,
  hour: new Date(new Date(payload.ts).getTime() + 4 * 3600 * 1000).toISOString().slice(11, 16),
  na_linii: s.na_linii !== undefined ? s.na_linii : null,
  available: s.available !== undefined ? s.available : null,
  gotov_bez_zakaza: s.gotov_bez_zakaza !== undefined ? s.gotov_bez_zakaza : null,
  gorit: s.gorit !== undefined ? s.gorit : null,
  ishem: s.ishem !== undefined ? s.ishem : null,
  slognost: s.slognost !== undefined ? s.slognost : null,
  board_total: b.total !== undefined ? b.total : null,
  board_burning: b.burning !== undefined ? b.burning : null,
  board_burning_free: b.burningNoDriver !== undefined ? b.burningNoDriver : null
};

try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}

let arr = [];
try { arr = JSON.parse(fs.readFileSync(file, 'utf8')); } catch (e) { arr = []; }
if (!Array.isArray(arr)) arr = [];
arr.push(point);

const cut = Date.now() - 8 * 24 * 3600 * 1000;
arr = arr.filter(function (p) { return new Date(p.ts).getTime() > cut; });

fs.writeFileSync(file, JSON.stringify(arr));

return [{ json: { ok: true, wrote: point, totalPoints: arr.length } }];

