        slognost: Number(L.slognost),
        slognost2: Number(L.slognost2),
        v_rabote: Number(L.v_rabote)
      }]);
    } catch (e) { return JSON.stringify([]); }
  });
  try { out.stats = JSON.parse(statsRaw); } catch (e) { out.stats = []; }

  await page.goto('https://1165.upphone.ru:4422/web/cab/1165/monitoring/orders', { waitUntil: 'domcontentloaded', timeout: 45000 });
  await new Promise(r => setTimeout(r, 5000));

  const boardRaw = await page.evaluate(() => {
    try {
      const rows = window.$('#orders-table').jqxGrid('getrows') || [];
      let burning = 0, free = 0;
      rows.forEach(function (r) {
        if (String(r.status) === 'burning') {
          burning++;
          if (!r.pozivnoi) free++;
        }
      });
      return JSON.stringify({ total: rows.length, burning: burning, burningNoDriver: free });
    } catch (e) { return JSON.stringify({ total: null, burning: null, burningNoDriver: null }); }
  });
  try { out.board = JSON.parse(boardRaw); } catch (e) { out.board = {}; }

  return { data: JSON.stringify(out), type: 'application/json' };
}

